        {aiSummary && (
          <div className="mb-6 p-5 ai-summary-gradient rounded-xl border border-blue-200 animate-in fade-in duration-1000">
             <h3 className="text-blue-800 font-bold text-sm mb-2 uppercase tracking-wider flex items-center gap-2">
                <span className="animate-pulse">✨</span> {t.aiSummaryTitle}
             </h3>
             <p className="text-blue-900 italic leading-relaxed text-lg">
                "{aiSummary}"
             </p>
          </div>
        )}

        <div className="prose prose-slate max-w-none text-slate-700" dangerouslySetInnerHTML={{ __html: t.proposalDescription }} />
      </div>

      <div className="bg-white rounded-2xl shadow-lg border border-slate-200/80">
        <div className={`p-6 border-b border-slate-200/80 ${language === 'ar' ? 'text-right' : 'text-left'}`}>
          <h2 className="text-2xl font-bold text-slate-800">{t.clientInfoTitle}</h2>
        </div>
        <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className={`${language === 'ar' ? 'text-right' : 'text-left'}`}>
            <label className="block text-sm font-medium text-slate-700">{t.proposalDateLabel}</label>
            <p className="mt-1 text-md text-slate-900 font-semibold">{formattedDate}</p>
          </div>
          <div className="hidden md:block"></div>
          <div className={`${language === 'ar' ? 'text-right' : 'text-left'}`}>
            <label htmlFor="name" className="block text-sm font-medium text-slate-700">{t.clientNameLabel}</label>
            <input
              type="text"
