              className="mt-1 block w-full px-4 py-2 bg-white border border-slate-300 rounded-xl text-sm shadow-sm placeholder-slate-400 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 disabled:bg-slate-50"
            />
          </div>
          <div className={`${language === 'ar' ? 'text-right' : 'text-left'}`}>
            <label htmlFor="phone" className="block text-sm font-medium text-slate-700">{t.clientPhoneLabel}</label>
            <div className={`mt-1 flex rounded-xl shadow-sm overflow-hidden ${language === 'ar' ? 'flex-row-reverse' : 'flex-row'}`}>
                <select
                    name="countryCode"
                    id="countryCode"
                    value={clientInfo.countryCode}
                    onChange={onClientInfoChange}
                    disabled={isClientMode}
                    className="block appearance-none border border-slate-300 py-2 bg-slate-50 text-sm text-slate-900 px-3 focus:outline-none"
                >
                    {countries.map(country => (
                        <option key={country.code} value={country.dial_code}>{`${country.code} (${country.dial_code})`}</option>
                    ))}
                </select>
                <input
                    type="tel"
                    name="phone"
                    id="phone"
                    value={clientInfo.phone}
