interface TotalBarProps {
  subTotalPrice: number;
  finalTotalPrice: number;
  discount: number;
  discountPercentage: number;
  onSendEmail: () => void;
  onClearSelection: () => void;
  onGenerateAI: () => void;
  onCopyLink: () => string;
  isAiLoading: boolean;
  language: 'ar' | 'en';
  t: Translation;
  actionType: string | null;
  formError: string;
  isClientMode: boolean;
}

const TotalBar: React.FC<TotalBarProps> = ({
  subTotalPrice,
  finalTotalPrice,
  discount,
  discountPercentage,
  onSendEmail,
  onClearSelection,
  onGenerateAI,
  onCopyLink,
  isAiLoading,
  language,
  t,
  actionType,
  formError,
  isClientMode,
}) => {
  const [copied, setCopied] = useState(false);

  if (finalTotalPrice <= 0 && !formError) return null;

  const handleCopy = () => {
    onCopyLink();
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="sticky bottom-0 z-50 bg-white/95 backdrop-blur-md border-t border-slate-200 shadow-2xl print:hidden">
