          <div className="flex items-baseline gap-2">
            <span className="text-lg font-medium text-slate-500">{t.totalPrice}:</span>
            <span className="text-4xl font-black text-slate-900">${finalTotalPrice.toLocaleString()}</span>
          </div>
          {discountPercentage > 0 && (
            <p className="text-sm text-blue-600 font-bold mt-1">
              {t.totalDiscountApplied(discountPercentage)}
            </p>
          )}
        </div>

        <div className="flex flex-wrap items-center gap-2 justify-center">
          {!isClientMode && finalTotalPrice > 0 && (
            <>
              <button
                onClick={onGenerateAI}
                disabled={isAiLoading}
                className="px-4 py-2 text-sm font-bold rounded-xl border-2 border-blue-100 bg-blue-50 text-blue-700 hover:bg-blue-100 disabled:opacity-50 transition-all flex items-center gap-2"
              >
                {isAiLoading ? '✨ ' + t.generating : '✨ ' + t.generateAISummary}
              </button>
              <button
                onClick={handleCopy}
                className="px-4 py-2 text-sm font-bold rounded-xl bg-slate-100 text-slate-700 hover:bg-slate-200 transition-all"
              >
                {copied ? t.linkCopied : t.copyProposalLink}
