import React, { useState, useEffect } from 'react';
import { Translation } from '../i18n';

interface TotalBarProps {
  finalTotalPrice: number;
  discountPercentage: number;
  onAction: () => void;
  onClear: () => void;
  onAI: () => void;
  onCopy: () => string;
  isAiLoading: boolean;
  language: 'ar' | 'en';
  t: Translation;
  formError: string;
  isClientMode: boolean;
}

const TotalBar: React.FC<TotalBarProps> = ({
  finalTotalPrice,
  discountPercentage,
  onAction,
  onClear,
  onAI,
  onCopy,
  isAiLoading,
  language,
  t,
  formError,
  isClientMode,
}) => {
  const [copied, setCopied] = useState(false);
  const [shouldAnimate, setShouldAnimate] = useState(false);

  useEffect(() => {
    if (finalTotalPrice > 0) {
      setShouldAnimate(true);
      const timer = setTimeout(() => setShouldAnimate(false), 500);
      return () => clearTimeout(timer);
    }
  }, [finalTotalPrice]);

  if (finalTotalPrice <= 0 && !formError) return null;

  const handleCopy = () => {
    onCopy();
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="sticky bottom-0 z-50 bg-white/95 backdrop-blur-md border-t border-slate-200 shadow-[0_-10px_40px_rgba(0,0,0,0.1)] print:hidden">
      <div className={`max-w-4xl mx-auto p-4 flex flex-col md:flex-row items-center justify-between gap-4 ${language === 'ar' ? 'md:flex-row-reverse' : ''}`}>
        <div className={`flex-grow ${language === 'ar' ? 'text-right' : 'text-left'}`}>
          <div className="flex items-baseline gap-2">
            <span className="text-lg font-medium text-slate-500">{t.totalPrice}:</span>
            <span className={`text-4xl font-black text-slate-900 transition-all duration-300 ${shouldAnimate ? 'scale-110 text-blue-600' : 'scale-100'}`}>
              ${finalTotalPrice.toLocaleString()}
            </span>
          </div>
          {discountPercentage > 0 && (
            <p className="text-sm text-blue-600 font-bold mt-1 flex items-center gap-1">
              <span className="animate-pulse">●</span> {t.totalDiscountApplied(discountPercentage)}
            </p>
          )}
        </div>

        <div className="flex flex-wrap items-center gap-2 justify-center">
          {finalTotalPrice > 0 && (
            <>
              <button
                onClick={onAI}
                disabled={isAiLoading}
                className="px-4 py-2 text-sm font-bold rounded-xl border-2 border-blue-100 bg-gradient-to-r from-blue-50 to-indigo-50 text-blue-700 hover:from-blue-100 hover:to-indigo-100 disabled:opacity-50 transition-all flex items-center gap-2"
              >
                {isAiLoading ? <span className="animate-spin">✨</span> : '✨'} {isAiLoading ? t.generating : t.generateAISummary}
              </button>
              <button
                onClick={handleCopy}
                className="px-4 py-2 text-sm font-bold rounded-xl bg-slate-100 text-slate-700 hover:bg-slate-200 transition-all"
              >
                {copied ? t.linkCopied : t.copyProposalLink}
              </button>
            </>
          )}

          <button
            onClick={onAction}
            className="px-6 py-3 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-500/30 active:scale-95 transition-all"
          >
            {isClientMode ? t.sendProposal : t.sendEmail}
          </button>

          {!isClientMode && (
            <button
              onClick={onClear}
              className="px-4 py-3 text-slate-400 hover:text-red-500 font-bold transition-colors"
            >
              {t.clearSelection}
            </button>
          )}
        </div>
      </div>
      {formError && (
        <div className="bg-red-50 p-3 text-center text-red-600 text-sm font-bold border-t border-red-100">
          {formError}
        </div>
      )}
    </div>
  );
};

export default TotalBar;

import React, { useState, useMemo, useEffect } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import StaticSection from './components/StaticSection';
import PricingSection from './components/PricingSection';
import TotalBar from './components/TotalBar';
import TermsAndConditions from './components/TermsAndConditions';
import { getServiceCategories, getUnitPrice } from './constants';
import { translations } from './i18n';
import type { ServiceCategory } from './types';
import PrintHeader from './components/PrintHeader';
import SuccessScreen from './components/SuccessScreen';
import DiscountCelebration from './components/DiscountCelebration';
import { GoogleGenAI } from "@google/genai";

const URL_PARAMS = new URLSearchParams(window.location.search);
const IS_CLIENT_MODE = URL_PARAMS.get('mode') === 'client';
const CLIENT_SERVICE_IDS = (URL_PARAMS.get('services') || '').split(',').filter(Boolean);

interface ClientInfo {
  name: string;
  phone: string;
  email: string;
  countryCode: string;
}

function getInitialLanguage() {
    try {
        const savedLang = localStorage.getItem('language');
        if (savedLang === 'en' || savedLang === 'ar') return savedLang;
    } catch (e) {}
    return 'ar';
}

function getInitialClientInfo(): ClientInfo {
    return {
        name: URL_PARAMS.get('name') || '',
        phone: URL_PARAMS.get('phone') || '',
        email: URL_PARAMS.get('email') || '',
        countryCode: URL_PARAMS.get('countryCode') || '+966',
    };
}

function App() {
  const [language, setLanguage] = useState<'ar' | 'en'>(getInitialLanguage());
  const [isClientMode] = useState(IS_CLIENT_MODE);
  const [clientInfo, setClientInfo] = useState<ClientInfo>(getInitialClientInfo);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategoryId, setSelectedCategoryId] = useState<string>('all');
  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedIds, setSelectedIds] = useState<string[]>(() => {
    if (IS_CLIENT_MODE && CLIENT_SERVICE_IDS.length > 0) return CLIENT_SERVICE_IDS;
    return [];
  });
  const [quantities, setQuantities] = useState<{ [id: string]: number }>({});
  const [proposalDate] = useState(new Date());
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [showCelebration, setShowCelebration] = useState(false);
  const [formError, setFormError] = useState('');

  const t = useMemo(() => translations[language], [language]);
  const allCategories = useMemo(() => getServiceCategories(language), [language]);

  const filteredCategories = useMemo(() => {
    let filtered = allCategories;
    if (selectedCategoryId !== 'all') {
      filtered = filtered.filter(cat => cat.id === selectedCategoryId);
    }
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      filtered = filtered.map(category => ({
        ...category,
        options: category.options.filter(option => 
          option.name.toLowerCase().includes(query) || 
          option.description?.toLowerCase().includes(query) ||
          option.items?.some(item => item.toLowerCase().includes(query))
        )
      })).filter(category => category.options.length > 0);
    }
    return filtered;
  }, [allCategories, selectedCategoryId, searchQuery]);

  useEffect(() => {
    document.documentElement.lang = language;
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
    document.body.style.fontFamily = "'Cairo', sans-serif";
  }, [language]);

  const toggleLanguage = () => {
    const newLang = language === 'ar' ? 'en' : 'ar';
    setLanguage(newLang);
    try { localStorage.setItem('language', newLang); } catch(e) {}
  };

  const handleClientInfoChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setClientInfo(prev => ({ ...prev, [name]: value }));
    if (formError) setFormError('');
  };

  const handleServiceToggle = (optionId: string, category: ServiceCategory) => {
    setSelectedIds(prevIds => {
      let newIds = [...prevIds];
      const isSelected = newIds.includes(optionId);
      if (category.isRadio) {
        category.options.forEach(opt => {
          const index = newIds.indexOf(opt.id);
          if (index > -1) newIds.splice(index, 1);
        });
        if (!isSelected) newIds.push(optionId);
      } else if (category.isPhased) {
        const selectedOptionIndex = category.options.findIndex(o => o.id === optionId);
        category.options.forEach(opt => {
          const index = newIds.indexOf(opt.id);
          if (index > -1) newIds.splice(index, 1);
        });
        if (!isSelected) {
          for (let i = 0; i <= selectedOptionIndex; i++) {
            newIds.push(category.options[i].id);
          }
        }
      } else {
        if (isSelected) newIds = newIds.filter(id => id !== optionId);
        else newIds.push(optionId);
      }
      return newIds;
    });
  };

  const handleQuantityChange = (optionId: string, newQuantity: number) => {
    if (newQuantity >= 1) {
      setQuantities(prev => ({ ...prev, [optionId]: newQuantity }));
    }
  };

  const selectedOptions = useMemo(() => {
    const allOptions = allCategories.flatMap(c => c.options);
    return allOptions.filter(o => selectedIds.includes(o.id));
  }, [selectedIds, allCategories]);

  const subTotalPrice = useMemo(() => {
    return selectedOptions.reduce((total, option) => {
      const quantity = option.hasQuantity ? (quantities[option.id] || 1) : 1;
      const unitPrice = getUnitPrice(option, quantity);
      return total + (unitPrice * quantity);
    }, 0);
  }, [selectedOptions, quantities]);

  const discountPercentage = useMemo(() => {
    let base = 0;
    const count = selectedIds.length;
    if (count >= 10) base = 30;
    else if (count >= 8) base = 20;
    else if (count >= 4) base = 10;
    if (subTotalPrice > 5000) base += 5;
    return base;
  }, [selectedIds.length, subTotalPrice]);

  const discount = (subTotalPrice * discountPercentage) / 100;
  const finalTotalPrice = subTotalPrice - discount;

  const generateAISummary = async () => {
    if (selectedOptions.length === 0) return;
    setIsAiLoading(true);
    try {
      // Use process.env.API_KEY directly as per guidelines
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const serviceNames = selectedOptions.map(o => o.name).join(', ');
      const prompt = `As O2Graphic design agency, write a professional paragraph (in ${language === 'ar' ? 'Arabic' : 'English'}) for client ${clientInfo.name || 'valued partner'}. They chose: ${serviceNames}. Explain why this selection is cohesive and powerful. Keep it under 80 words.`;
      const response = await ai.models.generateContent({ 
        model: 'gemini-3-flash-preview', 
        contents: prompt 
      });
      setAiSummary(response.text || null);
    } catch (e) { 
      console.error("Gemini Error:", e);
      setAiSummary(language === 'ar' ? "اختيارك لهذه الخدمات يعكس رؤية احترافية واهتماماً دقيقاً ببناء هوية بصرية متكاملة." : "Your selection reflects a professional vision and deep interest in building a comprehensive visual identity.");
    } finally { 
      setIsAiLoading(false); 
    }
  };

  const copyProposalLink = () => {
    const params = new URLSearchParams();
    params.set('mode', 'client');
    params.set('services', selectedIds.join(','));
    if (clientInfo.name) params.set('name', clientInfo.name);
    if (clientInfo.phone) params.set('phone', clientInfo.phone);
    if (clientInfo.countryCode) params.set('countryCode', clientInfo.countryCode);
    const link = `${window.location.origin}${window.location.pathname}?${params.toString()}`;
    try { navigator.clipboard.writeText(link); } catch(e) {}
    return link;
  };

  const handleAction = () => {
    if (!clientInfo.name) {
      setFormError(t.fillInfoAlert);
      return;
    }
    const message = `*${t.proposalTitle}*\n*${t.clientNameLabel}:* ${clientInfo.name}\n*${t.totalPrice}:* $${finalTotalPrice.toLocaleString()}\n\nDetails: ${copyProposalLink()}`;
    window.open(`https://wa.me/+905342006606?text=${encodeURIComponent(message)}`, '_blank');
  };

  return (
    <div className="bg-transparent min-h-screen font-['Cairo']">
      <Header language={language} toggleLanguage={toggleLanguage} />
      <PrintHeader />
      <main className="max-w-4xl mx-auto p-4 md:p-8 space-y-8 print:p-0">
        <StaticSection 
          t={t} language={language} clientInfo={clientInfo} 
          onClientInfoChange={handleClientInfoChange}
          proposalDate={proposalDate} isClientMode={isClientMode} aiSummary={aiSummary}
          emailError=""
        />
        <PricingSection
          categories={filteredCategories} allCategories={allCategories}
          selectedIds={selectedIds} onServiceToggle={handleServiceToggle}
          quantities={quantities} onQuantityChange={handleQuantityChange}
          language={language} t={t} searchQuery={searchQuery}
          setSearchQuery={setSearchQuery} selectedCategoryId={selectedCategoryId}
          setSelectedCategoryId={setSelectedCategoryId}
        />
        <TermsAndConditions t={t} language={language} />
      </main>
      <Footer />
      <TotalBar
        finalTotalPrice={finalTotalPrice} discountPercentage={discountPercentage}
        onAction={handleAction} onClear={() => { setSelectedIds([]); setAiSummary(null); }}
        onAI={generateAISummary} onCopy={copyProposalLink}
        isAiLoading={isAiLoading} language={language} t={t}
        formError={formError} isClientMode={isClientMode}
      />
      {showSuccessScreen && <SuccessScreen t={t} isClientMode={isClientMode} onClose={() => setShowSuccessScreen(false)} />}
      {showCelebration && <DiscountCelebration t={t} discountPercentage={discountPercentage} savedAmount={discount} onClose={() => setShowCelebration(false)} />}
    </div>
  );
}

export default App;

import React from 'react';
import type { ServiceOption } from '../types';
import { getUnitPrice } from '../constants';
import type { Translation } from '../i18n';

interface PricingOptionProps {
  option: ServiceOption;
  isSelected: boolean;
  onToggle: () => void;
  quantity: number;
  onQuantityChange: (newQuantity: number) => void;
  isRadio?: boolean;
  language: 'ar' | 'en';
  t: Translation;
  isClientMode: boolean;
}

const CheckIcon = ({ className = "h-4 w-4" }: { className?: string }) => (
    <svg className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
    </svg>
);

const QuantitySelector: React.FC<{
    quantity: number,
    onQuantityChange: (newQuantity: number) => void,
    t: Translation,
    label?: string,
}> = ({ quantity, onQuantityChange, t, label }) => {
    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = parseInt(e.target.value, 10);
        if (!isNaN(val)) {
            onQuantityChange(val);
        } else if (e.target.value === '') {
            onQuantityChange(0); 
        }
    };

    const handleBlur = () => {
        if (quantity < 1) onQuantityChange(1);
    };

    return (
        <div className="flex flex-col gap-1.5 mt-4" onClick={(e) => e.stopPropagation()}>
            {label && <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">{label}</span>}
            <div className="flex items-center bg-white border border-slate-200 rounded-full shadow-sm hover:shadow-md transition-all duration-300 overflow-hidden h-10 w-fit min-w-[110px]">
                <button
                    onClick={(e) => { e.stopPropagation(); onQuantityChange(quantity + 1); }}
                    className="w-9 h-full flex items-center justify-center text-slate-500 hover:bg-slate-50 hover:text-blue-600 transition-all duration-200 font-bold text-lg active:scale-90"
                    aria-label={t.increaseQuantity}
                >
                    +
                </button>
                <div className="flex-1 bg-white h-[70%] my-auto flex items-center justify-center border-x border-slate-100 min-w-[40px]">
                    <input
                        type="number"
                        value={quantity === 0 ? '' : quantity}
                        onChange={handleInputChange}
                        onBlur={handleBlur}
                        className="w-full bg-transparent border-none text-slate-900 font-black text-center text-base focus:outline-none focus:ring-0 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none p-0 selection:bg-blue-100"
                        aria-label={t.currentQuantity}
                    />
                </div>
                <button
                    onClick={(e) => { e.stopPropagation(); onQuantityChange(Math.max(1, quantity - 1)); }}
                    disabled={quantity <= 1}
                    className="w-9 h-full flex items-center justify-center text-slate-500 hover:bg-slate-50 hover:text-red-500 disabled:opacity-20 transition-all duration-200 font-bold text-lg active:scale-90"
                    aria-label={t.decreaseQuantity}
                >
                    −
                </button>
            </div>
        </div>
    );
};


const PricingOption: React.FC<PricingOptionProps> = ({
  option,
  isSelected,
  onToggle,
  quantity,
  onQuantityChange,
  isRadio,
  language,
  t,
  isClientMode,
}) => {
    const selectorType = isRadio ? 'radio' : 'checkbox';
    const currentUnitPrice = getUnitPrice(option, quantity);
    const totalOptionPrice = currentUnitPrice * (option.hasQuantity ? quantity : 1);

    return (
        <div
            onClick={onToggle}
            className={`
                relative p-5 border transition-all duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] transform
                ${isSelected
                    ? 'bg-gradient-to-br from-blue-50/80 to-indigo-50/80 border-blue-400 shadow-xl scale-[1.01] ring-1 ring-blue-400/20 z-10 rounded-3xl'
                    : 'bg-white border-slate-100 rounded-2xl hover:border-blue-200 hover:shadow-lg hover:translate-y-[-4px] hover:bg-slate-50/30'
                }
                cursor-pointer
            `}
            role={selectorType}
            aria-checked={isSelected}
            aria-label={option.name}
            tabIndex={0}
            onKeyDown={(e) => { if (e.key === ' ' || e.key === 'Enter') { e.preventDefault(); onToggle(); } }}
        >
            <div className="flex items-start gap-5">
                <div className={`
                    flex-shrink-0 w-6 h-6 mt-1 border-2 flex items-center justify-center transition-all duration-500 ease-out
                    ${isRadio ? 'rounded-full' : 'rounded-lg'}
                    ${isSelected ? 'bg-blue-600 border-blue-600 text-white scale-110 shadow-lg shadow-blue-500/30' : 'bg-white border-slate-200'}
                `}>
                    <div className={`transform transition-all duration-500 ${isSelected ? 'scale-100 opacity-100' : 'scale-0 opacity-0'}`}>
                         {isRadio ? <div className="w-2 h-2 bg-white rounded-full shadow-md"></div> : <CheckIcon className="h-3.5 w-3.5" />}
                    </div>
                </div>

                <div className="flex-grow">
                    <div className="flex flex-col sm:flex-row justify-between sm:items-start gap-4">
                        <div className="flex flex-col gap-1">
                            <h4 className={`text-lg font-black transition-colors duration-300 ${isSelected ? 'text-blue-900' : 'text-slate-800'}`}>
                                {option.name}
                            </h4>
                            {option.items && (
                                <ul className={`mt-3 text-sm text-slate-500 space-y-2 ${language === 'ar' ? 'pr-5' : 'pl-5'} border-l-2 border-slate-100`}>
                                    {option.items.map((item, index) => (
                                        <li key={index} className="leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: item.replace(/__(.*?)__/g, '<strong class="text-slate-700 font-black">$1</strong>') }} />
                                    ))}
                                </ul>
                            )}
                        </div>

                        <div className={`flex flex-col transition-all duration-300 ${language === 'ar' ? 'sm:text-left items-end' : 'sm:text-right items-start'} shrink-0`}>
                            {option.hasQuantity && quantity > 1 ? (
                                <>
                                    <span className="text-2xl font-black text-blue-600 tracking-tighter transition-all">
                                        ${totalOptionPrice.toLocaleString()}
                                    </span>
                                    <span className="text-[10px] text-slate-400 font-black mt-1 bg-slate-100 px-2 py-0.5 rounded-full">
                                        {quantity} × ${currentUnitPrice.toLocaleString()}
                                    </span>
                                </>
                            ) : (
                                <div className="flex flex-col items-end">
                                    <span className="text-2xl font-black tracking-tighter text-slate-900 transition-all">
                                        ${currentUnitPrice.toLocaleString()}
                                    </span>
                                    {option.hasQuantity && (
                                        <span className="text-[10px] text-slate-400 font-black mt-1 uppercase tracking-tighter">
                                            {option.priceSuffix || t.perPageSuffix}
                                        </span>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>

                    {option.hasQuantity && (
                        <div className="flex justify-end sm:justify-start">
                            <QuantitySelector quantity={quantity} onQuantityChange={onQuantityChange} t={t} label={option.quantityLabel} />
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

