export const translations = { en, ar };

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import StaticSection from './components/StaticSection';
import PricingSection from './components/PricingSection';
import TotalBar from './components/TotalBar';
import TermsAndConditions from './components/TermsAndConditions';
import { getServiceCategories, getUnitPrice } from './constants';
import { translations } from './i18n';
import type { ServiceOption, ServiceCategory } from './types';
import PrintHeader from './components/PrintHeader';
import SuccessScreen from './components/SuccessScreen';
import DiscountCelebration from './components/DiscountCelebration';
import { isEmailConfigured, sendProposalEmails } from './email';
import { formatCurrency } from './utils/format';

const URL_PARAMS = new URLSearchParams(window.location.search);
const IS_CLIENT_MODE = URL_PARAMS.get('mode') === 'client' && URL_PARAMS.has('services');
const CLIENT_SERVICE_IDS = (URL_PARAMS.get('services') || '').split(',').filter(Boolean);

interface ClientInfo {
  name: string;
  phone: string;
  email: string;
  countryCode: string;
}

function getInitialLanguage() {
    const savedLang = localStorage.getItem('language');
    if (savedLang === 'en' || savedLang === 'ar') {
        return savedLang;
    }
    return 'ar';
}

function getInitialClientInfo(): ClientInfo {
    return {
        name: URL_PARAMS.get('name') || '',
        phone: URL_PARAMS.get('phone') || '',
        email: URL_PARAMS.get('email') || '',
        countryCode: URL_PARAMS.get('countryCode') || '+966',
    };
}

function App() {
  const [language, setLanguage] = useState<'ar' | 'en'>(getInitialLanguage());
  const [isClientMode] = useState(IS_CLIENT_MODE);
  const [clientInfo, setClientInfo] = useState<ClientInfo>(getInitialClientInfo);
  const [emailError, setEmailError] = useState('');
  const [formError, setFormError] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>(() => {
    if (IS_CLIENT_MODE) {
      return CLIENT_SERVICE_IDS;
    }
    return [];
  });
  const [quantities, setQuantities] = useState<{ [id: string]: number }>({});
  const [actionType, setActionType] = useState<string | null>(null);
  const [proposalDate] = useState(new Date());
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [showCelebration, setShowCelebration] = useState(false);

  const prevDiscountPercentageRef = useRef(0);

  const t = useMemo(() => translations[language], [language]);
  const serviceCategories = useMemo(() => {
    const allCategories = getServiceCategories(language);
    // In Dynamic mode, we show all categories so client can see alternatives, 
    // but pre-select the ones from the URL.
    return allCategories;
  }, [language]);

  useEffect(() => {
    document.documentElement.lang = language;
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.classList.remove('lang-en', 'lang-ar');
    document.documentElement.classList.add(`lang-${language}`);
  }, [language]);

  const toggleLanguage = () => {
    const newLang = language === 'ar' ? 'en' : 'ar';
    setLanguage(newLang);
    localStorage.setItem('language', newLang);
  };

  const validateEmail = (email: string) => {
    if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setEmailError(t.emailError);
    } else {
      setEmailError('');
    }
  };

  const handleClientInfoChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setClientInfo(prev => ({ ...prev, [name]: value }));
    if (formError) setFormError('');
    if (name === 'email') {
      validateEmail(value);
    }
  };

  const handleServiceToggle = (optionId: string, category: ServiceCategory) => {
    // Dynamic interaction allowed for everyone
    setSelectedIds(prevIds => {
      let newIds = [...prevIds];
      const isSelected = newIds.includes(optionId);

      if (category.isRadio) {
        category.options.forEach(opt => {
          const index = newIds.indexOf(opt.id);
          if (index > -1) newIds.splice(index, 1);
        });
        if (!isSelected) {
          newIds.push(optionId);
        }
      } else if (category.isPhased) {
        const selectedOptionIndex = category.options.findIndex(o => o.id === optionId);
        category.options.forEach(opt => {
          const index = newIds.indexOf(opt.id);
          if (index > -1) newIds.splice(index, 1);
        });
        if (!isSelected) {
          for (let i = 0; i <= selectedOptionIndex; i++) {
            newIds.push(category.options[i].id);
          }
        }
      } else {
        if (isSelected) {
          newIds = newIds.filter(id => id !== optionId);
        } else {
          newIds.push(optionId);
        }
      }
      return newIds;
    });
  };

  const handleQuantityChange = (optionId: string, newQuantity: number) => {
    if (newQuantity >= 1) {
      setQuantities(prev => ({ ...prev, [optionId]: newQuantity }));
    }
  };

  const handleClearSelection = () => {
    setSelectedIds([]);
    setQuantities({});
  };

  const selectedOptions = useMemo(() => {
    const allOptions = serviceCategories.flatMap(c => c.options);
    return allOptions.filter(o => selectedIds.includes(o.id));
  }, [selectedIds, serviceCategories]);

  const subTotalPrice = useMemo(() => {
    return selectedOptions.reduce((total, option) => {
      const quantity = option.hasQuantity ? (quantities[option.id] || 1) : 1;
      const unitPrice = getUnitPrice(option, quantity);
      return total + (unitPrice * quantity);
    }, 0);
  }, [selectedOptions, quantities]);

  const discountPercentage = useMemo(() => {
    let basePercentage = 0;
    const count = selectedIds.length;

    if (count >= 10) {
      basePercentage = 30;
    } else if (count >= 8) {
      basePercentage = 20;
    } else if (count >= 4) {
      basePercentage = 10;
    }

    let bonusPercentage = 0;
    if (subTotalPrice > 5000) {
      bonusPercentage = 5;
    }

    return basePercentage + bonusPercentage;
  }, [selectedIds.length, subTotalPrice]);

  const discount = useMemo(() => (subTotalPrice * discountPercentage) / 100, [subTotalPrice, discountPercentage]);
  const finalTotalPrice = useMemo(() => subTotalPrice - discount, [subTotalPrice, discountPercentage]);

  useEffect(() => {
    if (discountPercentage > prevDiscountPercentageRef.current) {
        setShowCelebration(true);
    }
    prevDiscountPercentageRef.current = discountPercentage;
  }, [discountPercentage]);

  const validateInfo = useCallback(() => {
    const { name, phone, email } = clientInfo;
    const isEmailValid = email && !emailError;
    if (!name || !phone || !isEmailValid) {
      setFormError(t.fillInfoAlert);
      return false;
    }
    setFormError('');
    return true;
  }, [clientInfo, emailError, t.fillInfoAlert]);

  const handleSendViaWhatsApp = () => {
    setFormError('');
    if (!validateInfo()) return;

    const formattedDate = proposalDate.toLocaleDateString(language === 'ar' ? 'ar-EG' : 'en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
    });

    const fullPhoneNumber = `${clientInfo.countryCode}${clientInfo.phone}`;

    const servicesText = selectedOptions.map(option => {
        const quantity = option.hasQuantity ? (quantities[option.id] || 1) : 1;
        const unitPrice = getUnitPrice(option, quantity);
        const price = unitPrice * quantity;
        const quantityText = option.hasQuantity ? ` (${quantity} × ${formatCurrency(unitPrice)})` : '';
        return `- ${option.name}${quantityText}: *${formatCurrency(price)}*`;
    }).join('\n');

    const message = `
*${t.proposalTitle}*

*${t.clientInfoTitle}:*
${t.clientNameLabel}: ${clientInfo.name}
${t.clientPhoneLabel}: ${fullPhoneNumber}
${t.clientEmailLabel}: ${clientInfo.email}
${t.proposalDateLabel}: ${formattedDate}

*${t.selectedServicesTitle}:*
${servicesText}

*${t.priceSummaryTitle}:*
${t.subtotal}: ${formatCurrency(subTotalPrice)}
${language === 'en' ? t.discountLabel(discountPercentage) : `خصم (${discountPercentage}%)`}: -${formatCurrency(discount)}
*${t.totalPrice}: ${formatCurrency(finalTotalPrice)}*

${t.proposalTo(clientInfo.name)}
    `.trim().replace(/^\s+/gm, "");

    const whatsappNumber = '+905342006606';
    const encodedMessage = encodeURIComponent(message);
    const whatsappUrl = `https://wa.me/${whatsappNumber}?text=${encodedMessage}`;

    window.open(whatsappUrl, '_blank', 'noopener,noreferrer');
};

  const handleSubmission = () => {
    setFormError('');
    if (!validateInfo() || actionType) return;

    if (!isEmailConfigured()) {
        setFormError(t.emailConfigMissing);
        return;
    }

    setActionType('email');

    sendProposalEmails({
      clientInfo,
      selectedOptions,
      quantities,
      subTotalPrice,
      discount,
      discountPercentage,
      finalTotalPrice,
      isClientSubmission: true,
      t,
      selectedIds,
      proposalDate
    })
      .then((response) => {
        setShowSuccessScreen(true);
        setActionType(null);
      }, (err) => {
        setFormError(t.emailSendError);
        setActionType(null);
      });
  };

  return (
    <div className="bg-transparent min-h-screen">
      <Header 
        language={language}
        toggleLanguage={toggleLanguage}
      />
      <PrintHeader />
      <main className="max-w-4xl mx-auto p-4 md:p-8 space-y-8 print:p-0 print:mx-0 print:max-w-full">
        <StaticSection 
          t={t}
          language={language}
          clientInfo={clientInfo}
          onClientInfoChange={handleClientInfoChange}
          emailError={emailError}
          proposalDate={proposalDate}
          isClientMode={false} // Allow editing info in client mode too
        />
        <PricingSection
          categories={serviceCategories}
          selectedIds={selectedIds}
          onServiceToggle={handleServiceToggle}
          quantities={quantities}
          onQuantityChange={handleQuantityChange}
          language={language}
          t={t}
          isClientMode={false} // Dynamic interaction always enabled
        />
        <TermsAndConditions t={t} language={language} />
      </main>
      <Footer language={language} />
      <TotalBar
        subTotalPrice={subTotalPrice}
        finalTotalPrice={finalTotalPrice}
        discount={discount}
        discountPercentage={discountPercentage}
        onSendEmail={isClientMode ? handleSubmission : handleSendViaWhatsApp}
        onClearSelection={handleClearSelection}
        language={language}
        t={t}
        actionType={actionType}
        formError={formError}
        isClientMode={isClientMode}
      />
      {showSuccessScreen && (
        <SuccessScreen 
            t={t}
            isClientMode={isClientMode}
            onClose={() => setShowSuccessScreen(false)}
        />
      )}
      {showCelebration && (
        <DiscountCelebration 
            t={t}
            discountPercentage={discountPercentage}
            savedAmount={discount}
            onClose={() => setShowCelebration(false)}
        />
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import type { ServiceOption } from '../types';
import { getUnitPrice } from '../constants';
import type { Translation } from '../i18n';
import { formatCurrency } from '../utils/format';

interface PricingOptionProps {
  option: ServiceOption;
  isSelected: boolean;
  onToggle: () => void;
  quantity: number;
  onQuantityChange: (newQuantity: number) => void;
  isRadio?: boolean;
  language: 'ar' | 'en';
  t: Translation;
  isClientMode: boolean;
}

const CheckIcon = ({ className = "h-4 w-4" }: { className?: string }) => (
    <svg className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
    </svg>
);

const QuantitySelector: React.FC<{
    quantity: number,
    onQuantityChange: (newQuantity: number) => void,
    t: Translation,
    label?: string,
}> = ({ quantity, onQuantityChange, t, label }) => {
    const [isPulsing, setIsPulsing] = useState(false);

    useEffect(() => {
        setIsPulsing(true);
        const timer = setTimeout(() => setIsPulsing(false), 300);
        return () => clearTimeout(timer);
    }, [quantity]);

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = parseInt(e.target.value, 10);
        if (!isNaN(val)) {
            onQuantityChange(val);
        } else if (e.target.value === '') {
            onQuantityChange(0); // Allow typing from scratch
        }
    };

    const handleBlur = () => {
        if (quantity < 1) onQuantityChange(1);
    };

    return (
        <div className="flex items-center gap-3" onClick={(e) => e.stopPropagation()}>
            {label && <span className="text-sm font-medium text-slate-700">{label}</span>}
            <div className="flex items-center border border-slate-200 rounded-lg shadow-sm bg-white overflow-hidden h-9 transition-shadow hover:shadow-md" style={{ minWidth: '120px' }}>
                {/* Plus Button */}
                <button
                    onClick={(e) => { e.stopPropagation(); onQuantityChange(quantity + 1); }}
                    className="w-10 h-full flex items-center justify-center text-slate-400 hover:bg-slate-50 hover:text-blue-600 active:scale-90 transition-all font-bold text-xl"
                    aria-label={t.increaseQuantity}
                >
                    +
                </button>

                {/* Number Input */}
                <div className="flex-1 bg-white h-full flex items-center justify-center border-x border-slate-100">
                    <input
                        type="number"
                        value={quantity === 0 ? '' : quantity}
                        onChange={handleInputChange}
                        onBlur={handleBlur}
                        className={`w-full bg-transparent border-none text-slate-900 font-bold text-center text-base focus:outline-none focus:ring-0 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none p-0 transition-transform ${isPulsing ? 'animate-value-pop' : ''}`}
                        aria-label={t.currentQuantity}
                    />
                </div>

                {/* Minus Button */}
                <button
                    onClick={(e) => { e.stopPropagation(); onQuantityChange(Math.max(1, quantity - 1)); }}
                    disabled={quantity <= 1}
                    className="w-10 h-full flex items-center justify-center text-slate-400 hover:bg-slate-50 hover:text-red-500 disabled:opacity-20 active:scale-90 transition-all font-bold text-xl"
                    aria-label={t.decreaseQuantity}
                >
                    -
                </button>
            </div>
        </div>
    );
};


const PricingOption: React.FC<PricingOptionProps> = ({
  option,
  isSelected,
  onToggle,
  quantity,
  onQuantityChange,
  isRadio,
  language,
  t,
  isClientMode,
}) => {
    const [pricePulse, setPricePulse] = useState(false);
    const selectorType = isRadio ? 'radio' : 'checkbox';
    const currentUnitPrice = getUnitPrice(option, quantity);
    const totalOptionPrice = currentUnitPrice * (option.hasQuantity ? quantity : 1);

    useEffect(() => {
        setPricePulse(true);
        const timer = setTimeout(() => setPricePulse(false), 300);
        return () => clearTimeout(timer);
    }, [totalOptionPrice, isSelected]); // Pulsing on value change OR selection state change

    const handleToggle = () => {
        if (!isClientMode) {
            onToggle();
        }
    };

    return (
        <div
            onClick={handleToggle}
            className={`
                relative p-5 border rounded-2xl transition-all duration-500 ease-[cubic-bezier(0.34,1.56,0.64,1)] transform
                ${isSelected
                    ? 'bg-blue-50 border-blue-500 shadow-xl scale-[1.015] ring-2 ring-blue-500/20 z-10'
                    : `bg-white border-slate-200 hover:border-blue-300 hover:shadow-lg hover:translate-y-[-2px] hover:bg-slate-50`
                }
                ${isClientMode ? 'cursor-default pointer-events-none opacity-90' : 'cursor-pointer'}
            `}
            role={selectorType}
            aria-checked={isSelected}
            aria-label={option.name}
            tabIndex={isClientMode ? -1 : 0}
            onKeyDown={(e) => { if (!isClientMode && (e.key === ' ' || e.key === 'Enter')) { e.preventDefault(); onToggle(); } }}
        >
            <div className="flex items-start gap-5">
                {/* Custom Checkbox/Radio */}
                <div className={`
                    flex-shrink-0 w-6 h-6 mt-1 border-2 flex items-center justify-center transition-all duration-300 ease-out
                    ${isRadio ? 'rounded-full' : 'rounded-lg'}
                    ${isSelected ? 'bg-blue-600 border-blue-600 text-white scale-110 shadow-md shadow-blue-200' : 'bg-white border-slate-300 group-hover:border-blue-400'}
                `}>
                    <div className={`transform transition-all duration-300 ${isSelected ? 'scale-100 opacity-100 rotate-0' : 'scale-0 opacity-0 -rotate-45'}`}>
                         {isRadio ? <div className="w-2.5 h-2.5 bg-white rounded-full shadow-sm"></div> : <CheckIcon className="h-4 w-4 stroke-[3]" />}
                    </div>
                </div>

                <div className="flex-grow">
                    <div className="flex flex-col sm:flex-row justify-between sm:items-start gap-3">
                        <div className="flex-1">
                            <h4 className={`text-lg font-bold transition-colors duration-300 ${isSelected ? 'text-blue-900' : 'text-slate-800'}`}>
                                {option.name}
                            </h4>
                        </div>
                        <div className={`transition-all duration-300 ${language === 'ar' ? 'sm:text-left' : 'sm:text-right'}`}>
                            <div className={`${pricePulse ? 'animate-value-pop' : ''}`}>
                                {option.hasQuantity && quantity > 1 && !isClientMode ? (
                                    <div className="flex flex-col items-end">
                                        <p className={`text-xl font-black ${isSelected ? 'text-blue-700' : 'text-slate-900'}`}>
                                            {formatCurrency(totalOptionPrice)}
                                        </p>
                                        <p className="text-xs text-slate-400 font-medium mt-0.5">
                                            ({quantity} × {formatCurrency(currentUnitPrice)})
                                        </p>
                                    </div>
                                ) : (
                                    <p className={`text-xl font-black ${isSelected ? 'text-blue-700' : 'text-slate-900'}`}>
                                        {formatCurrency(currentUnitPrice)}
                                        {option.hasQuantity && <span className="text-sm text-slate-400 font-normal"> {option.priceSuffix || t.perPageSuffix}</span>}
                                    </p>
                                )}
                            </div>
                        </div>
                    </div>

                    {option.items && (
                        <ul className={`mt-3 text-sm text-slate-600 space-y-1.5 ${language === 'ar' ? 'pr-4 border-r-2 border-slate-100' : 'pl-4 border-l-2 border-slate-100'} transition-opacity duration-300 ${isSelected ? 'opacity-100' : 'opacity-80'}`}>
                            {option.items.map((item, index) => (
                                <li key={index} className="leading-relaxed" dangerouslySetInnerHTML={{ __html: item.replace(/__(.*?)__/g, '<strong class="text-slate-800 font-bold">$1</strong>') }} />
                            ))}
                        </ul>
                    )}

                    <div className="mt-5 flex flex-wrap items-center gap-4">
                        {option.hasQuantity && !isClientMode && (
                            <QuantitySelector quantity={quantity} onQuantityChange={onQuantityChange} t={t} label={option.quantityLabel} />
                        )}
                    </div>
                </div>
            </div>

            {/* Print-only view */}
            {isSelected && (
                <div className="hidden print:block pt-3 border-t border-slate-100 mt-3">
                    <div className="flex justify-between items-baseline">
                        <div className="flex items-center gap-2">
                           <h4 className="font-bold text-sm text-black">{option.name}</h4>
                        </div>
                        <p className="font-semibold text-sm text-black">
                            {option.hasQuantity ? `${quantity} x ${formatCurrency(currentUnitPrice)}` : `${formatCurrency(currentUnitPrice)}`}
                        </p>
                    </div>
                    {option.hasQuantity && (
                        <div className="flex justify-end">
                            <p className="font-bold text-sm text-black">= {formatCurrency(totalOptionPrice)}</p>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default PricingOption;

import React, { useState, useEffect } from 'react';
import { Translation } from '../i18n';
import { formatCurrency } from '../utils/format';

interface TotalBarProps {
  subTotalPrice: number;
  finalTotalPrice: number;
  discount: number;
  discountPercentage: number;
  onSendEmail: () => void;
  onClearSelection: () => void;
  language: 'ar' | 'en';
  t: Translation;
  actionType: string | null;
  formError: string;
  isClientMode: boolean;
}

const WhatsAppIcon = () => (
    <svg 
        className="h-5 w-5" 
        fill="currentColor" 
        viewBox="0 0 24 24" 
        xmlns="http://www.w3.org/2000/svg"
    >
        <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z" />
    </svg>
);

const TotalBar: React.FC<TotalBarProps> = ({
  subTotalPrice,
  finalTotalPrice,
  discount,
  discountPercentage,
  onSendEmail,
  onClearSelection,
  language,
  t,
  actionType,
  formError,
  isClientMode,
}) => {
  const [pulseTotal, setPulseTotal] = useState(false);

  useEffect(() => {
    if (finalTotalPrice > 0) {
      setPulseTotal(true);
      const timer = setTimeout(() => setPulseTotal(false), 300);
      return () => clearTimeout(timer);
    }
  }, [finalTotalPrice]);

  if (finalTotalPrice <= 0 && !formError) {
    return null;
  }

  const discountText = discountPercentage > 0 && !isClientMode
    ? t.totalDiscountApplied(discountPercentage)
    : null;

  const isSending = actionType === 'email';

  return (
    <div className="sticky bottom-0 z-50 bg-white/90 backdrop-blur-md border-t border-slate-200 shadow-lg print:hidden">
      <div className={`max-w-4xl mx-auto p-4 flex flex-col sm:flex-row items-center justify-between gap-4 ${language === 'ar' ? 'sm:flex-row-reverse' : ''}`}>
        <div 
          className={`flex-grow ${language === 'ar' ? 'text-right' : 'text-left'}`}
          aria-live="polite"
          aria-atomic="true"
        >
          {finalTotalPrice > 0 && (
            <>
              <div className="flex items-baseline gap-2">
                <span className="text-lg font-medium text-slate-600">{t.totalPrice}:</span>
                <span className={`text-3xl font-extrabold text-slate-800 transition-transform inline-block ${pulseTotal ? 'animate-value-pop' : ''}`}>
                    {formatCurrency(finalTotalPrice)}
                </span>
                {discount > 0 && !isClientMode && (
                  <span className="text-base font-medium text-slate-500 line-through">{formatCurrency(subTotalPrice)}</span>
                )}
              </div>
              {discountText && (
                <p className="text-sm text-blue-600 font-medium mt-1">{discountText}</p>
              )}
            </>
          )}
        </div>
        <div className="flex flex-col gap-2 items-stretch flex-shrink-0 w-full sm:w-auto">
          {formError && (
            <p role="alert" className={`text-sm text-red-600 text-center ${language === 'ar' ? 'sm:text-right' : 'sm:text-left'}`}>
              {formError}
            </p>
          )}
          {finalTotalPrice > 0 && (
              <div className={`flex flex-col sm:flex-row items-center gap-2 ${language === 'ar' ? 'sm:flex-row-reverse' : ''}`}>
                <button
                  onClick={onSendEmail}
                  disabled={isSending}
                  className="w-full sm:w-auto justify-center flex items-center gap-2 px-6 py-3 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:bg-blue-300 transition-transform active:scale-95"
                >
                  {isClientMode ? (
                      isSending ? t.sending : t.sendProposal
                  ) : (
                    <>
                      <WhatsAppIcon />
                      {t.sendEmail}
                    </>
                  )}
                </button>
                {!isClientMode && (
                  <button
                    onClick={onClearSelection}
                    className="w-full sm:w-auto justify-center flex items-center px-6 py-3 border border-transparent text-sm font-medium rounded-md text-slate-700 bg-slate-100 hover:bg-slate-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-slate-500 transition-colors"
                  >
                    {t.clearSelection}
                  </button>
                )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default TotalBar;

