const TotalBar: React.FC<TotalBarProps> = ({
  subTotalPrice,
  finalTotalPrice,
  discount,
  discountPercentage,
  onSendEmail,
  onClearSelection,
  language,
  t,
  actionType,
  formError,
  isClientMode,
  appliedCoupon,
  onApplyCoupon,
}) => {
  const [pulseTotal, setPulseTotal] = useState(false);
  const [couponCode, setCouponCode] = useState('');
  const [couponError, setCouponError] = useState(false);

  useEffect(() => {
    if (finalTotalPrice > 0) {
      setPulseTotal(true);
      const timer = setTimeout(() => setPulseTotal(false), 300);
      return () => clearTimeout(timer);
    }
  }, [finalTotalPrice]);

  const handleApplyCoupon = () => {
    const coupon = VALID_COUPONS.find(c => c.code.toUpperCase() === couponCode.toUpperCase().trim());
    if (coupon) {
      onApplyCoupon(coupon);
      setCouponError(false);
      setCouponCode('');
    } else {
      setCouponError(true);
    }
  };

  const handleRemoveCoupon = () => {
    onApplyCoupon(null);
  };

  if (finalTotalPrice <= 0 && !formError) {
    return null;
  }

  const discountText = discountPercentage > 0 && !isClientMode
    ? t.totalDiscountApplied(discountPercentage)
