              <span className="text-xl md:text-2xl font-bold text-slate-500 tracking-tight">{t.totalPrice}:</span>
              <span className={`text-4xl md:text-6xl font-black text-slate-900 transition-transform inline-block ${pulseTotal ? 'animate-value-pop' : ''}`}>
                  {formatCurrency(finalTotalPrice)}
              </span>
              {discount > 0 && !isClientMode && (
                <span className="text-xl md:text-2xl font-bold text-red-500 line-through decoration-red-500/60 italic opacity-90">
                    {formatCurrency(subTotalPrice)}
                </span>
              )}
            </div>

            <div className={`flex flex-wrap gap-4 items-center ${language === 'ar' ? 'flex-row-reverse' : 'flex-row'}`}>
              {discountText && (
                <p className="text-sm md:text-base text-blue-600 font-bold bg-blue-50/80 px-4 py-1.5 rounded-full inline-block border border-blue-100/50 shadow-sm">
                  {discountText}
                </p>
              )}
              {discount > 0 && !isClientMode && (
                <p className="text-sm md:text-base text-green-600 font-black bg-green-50/80 px-4 py-1.5 rounded-full inline-block border border-green-100/50 shadow-sm">
                  {t.youSaved(formatCurrency(discount))}
                </p>
              )}
            </div>

            {/* Improved Coupon Input Area */}
            <div className={`mt-4 flex flex-col gap-2 ${language === 'ar' ? 'items-end' : 'items-start'}`}>
              {!appliedCoupon ? (
                <div className={`flex items-stretch gap-2.5 w-full max-w-[380px] ${language === 'ar' ? 'flex-row-reverse' : 'flex-row'}`}>
                  <div className="relative flex-1 group">
                    <input
                      type="text"
                      value={couponCode}
                      onChange={(e) => { setCouponCode(e.target.value); if(couponError) setCouponError(false); }}
                      onKeyDown={(e) => e.key === 'Enter' && handleApplyCoupon()}
                      placeholder={t.couponPlaceholder}
                      className={`w-full text-base h-12 px-5 bg-slate-50 text-slate-900 border-2 ${couponError ? 'border-red-400 bg-red-50 text-red-900' : 'border-slate-200 group-hover:border-slate-300 focus:border-blue-500 shadow-sm'} rounded-2xl focus:outline-none transition-all duration-200 placeholder:text-slate-400 font-black uppercase tracking-wider`}
                    />
                  </div>
                  <button
                    onClick={handleApplyCoupon}
                    className="h-12 px-10 bg-[#1e293b] text-white text-base font-black rounded-2xl hover:bg-[#0f172a] active:scale-95 transition-all shadow-lg shadow-slate-200 whitespace-nowrap"
                  >
                    {t.applyBtn}
                  </button>
                </div>
              ) : (
                <div className={`flex items-center gap-4 bg-blue-600 text-white px-5 py-2.5 rounded-2xl shadow-xl shadow-blue-200 transition-all duration-300 animate-in fade-in slide-in-from-top-3 ${language === 'ar' ? 'flex-row-reverse' : 'flex-row'}`}>
                  <div className="flex items-center gap-3">
                    <div className="bg-white/25 p-1.5 rounded-lg">
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" />
                      </svg>
                    </div>
                    <span className="text-sm font-black uppercase tracking-widest">
                      {appliedCoupon.code}
                    </span>
                    <span className="text-xs font-black bg-white/20 px-2 py-1 rounded-lg border border-white/20">
                      -{appliedCoupon.discount}%
                    </span>
                  </div>
                  <button 
                    onClick={handleRemoveCoupon}
                    className="p-1.5 hover:bg-white/20 rounded-full transition-colors"
                    aria-label={t.removeCoupon}
                  >
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              )}
              {couponError && (
                <p className="text-xs text-red-500 font-black animate-in fade-in slide-in-from-top-1 px-1">
                  {t.invalidCoupon}
                </p>
              )}
            </div>
          </div>
        </div>

        {/* Right Side: Action Buttons */}
        <div className="flex flex-col gap-3 flex-shrink-0 w-full md:w-auto">
          {formError && (
            <p role="alert" className={`text-sm text-red-600 font-black mb-1 ${language === 'ar' ? 'text-right' : 'text-left'}`}>
              {formError}
            </p>
          )}
          <div className={`flex flex-col sm:flex-row items-center gap-3 ${language === 'ar' ? 'sm:flex-row-reverse' : ''}`}>
            <button
              onClick={onSendEmail}
              disabled={isSending}
              className="w-full sm:w-auto min-w-[240px] justify-center flex items-center gap-3 px-10 py-5 border border-transparent text-lg font-black rounded-2xl shadow-[0_12px_40px_rgb(37,99,235,0.25)] text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:bg-blue-300 transition-all active:scale-[0.97] uppercase tracking-wider"
            >
              {isClientMode ? (
                  isSending ? t.sending : t.sendProposal
              ) : (
                <>
                  <WhatsAppIcon />
                  {t.sendEmail}
                </>
              )}
            </button>
            {!isClientMode && (
              <button
                onClick={onClearSelection}
                className="w-full sm:w-auto justify-center flex items-center px-8 py-5 border border-slate-200 text-lg font-bold rounded-2xl text-slate-500 bg-white hover:bg-slate-50 hover:text-slate-700 focus:outline-none transition-all duration-200 active:scale-95"
              >
                {t.clearSelection}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default TotalBar;

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import StaticSection from './components/StaticSection';
import PricingSection from './components/PricingSection';
import TotalBar from './components/TotalBar';
import TermsAndConditions from './components/TermsAndConditions';
import { getServiceCategories, getUnitPrice } from './constants';
import { translations } from './i18n';
import type { ServiceOption, ServiceCategory } from './types';
import PrintHeader from './components/PrintHeader';
import SuccessScreen from './components/SuccessScreen';
import DiscountCelebration from './components/DiscountCelebration';
import { isEmailConfigured, sendProposalEmails } from './email';
import { formatCurrency } from './utils/format';

const URL_PARAMS = new URLSearchParams(window.location.search);
const IS_CLIENT_MODE = URL_PARAMS.get('mode') === 'client' && URL_PARAMS.has('services');
const CLIENT_SERVICE_IDS = (URL_PARAMS.get('services') || '').split(',').filter(Boolean);

interface ClientInfo {
  name: string;
  phone: string;
  email: string;
  countryCode: string;
}

function getInitialLanguage() {
    const savedLang = localStorage.getItem('language');
    if (savedLang === 'en' || savedLang === 'ar') {
        return savedLang;
    }
    return 'ar';
}

function getInitialClientInfo(): ClientInfo {
    return {
        name: URL_PARAMS.get('name') || '',
        phone: URL_PARAMS.get('phone') || '',
        email: URL_PARAMS.get('email') || '',
        countryCode: URL_PARAMS.get('countryCode') || '+966',
    };
}

function App() {
  const [language, setLanguage] = useState<'ar' | 'en'>(getInitialLanguage());
  const [isClientMode] = useState(IS_CLIENT_MODE);
  const [clientInfo, setClientInfo] = useState<ClientInfo>(getInitialClientInfo);
  const [emailError, setEmailError] = useState('');
  const [formError, setFormError] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>(() => {
    if (IS_CLIENT_MODE) {
      return CLIENT_SERVICE_IDS;
    }
    return [];
  });
  const [quantities, setQuantities] = useState<{ [id: string]: number }>({});
  const [appliedCoupon, setAppliedCoupon] = useState<{ code: string; discount: number } | null>(null);
  const [actionType, setActionType] = useState<string | null>(null);
  const [proposalDate] = useState(new Date());
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [showCelebration, setShowCelebration] = useState(false);

  const prevDiscountPercentageRef = useRef(0);

  const t = useMemo(() => translations[language], [language]);
  const serviceCategories = useMemo(() => {
    const allCategories = getServiceCategories(language);
    return allCategories;
  }, [language]);

  useEffect(() => {
    document.documentElement.lang = language;
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.classList.remove('lang-en', 'lang-ar');
    document.documentElement.classList.add(`lang-${language}`);
  }, [language]);

  const toggleLanguage = () => {
    const newLang = language === 'ar' ? 'en' : 'ar';
    setLanguage(newLang);
    localStorage.setItem('language', newLang);
  };

  const validateEmail = (email: string) => {
    if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setEmailError(t.emailError);
    } else {
      setEmailError('');
    }
  };

  const handleClientInfoChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setClientInfo(prev => ({ ...prev, [name]: value }));
    if (formError) setFormError('');
    if (name === 'email') {
      validateEmail(value);
    }
  };

  const handleServiceToggle = (optionId: string, category: ServiceCategory) => {
    setSelectedIds(prevIds => {
      let newIds = [...prevIds];
      const isSelected = newIds.includes(optionId);

      if (category.isRadio) {
        category.options.forEach(opt => {
          const index = newIds.indexOf(opt.id);
          if (index > -1) newIds.splice(index, 1);
        });
        if (!isSelected) {
          newIds.push(optionId);
        }
      } else if (category.isPhased) {
        const selectedOptionIndex = category.options.findIndex(o => o.id === optionId);
        category.options.forEach(opt => {
          const index = newIds.indexOf(opt.id);
          if (index > -1) newIds.splice(index, 1);
        });
        if (!isSelected) {
          for (let i = 0; i <= selectedOptionIndex; i++) {
            newIds.push(category.options[i].id);
          }
        }
      } else {
        if (isSelected) {
          newIds = newIds.filter(id => id !== optionId);
        } else {
          newIds.push(optionId);
        }
      }
      return newIds;
    });
  };

  const handleQuantityChange = (optionId: string, newQuantity: number) => {
    if (newQuantity >= 1) {
      setQuantities(prev => ({ ...prev, [optionId]: newQuantity }));
    }
  };

  const handleClearSelection = () => {
    setSelectedIds([]);
    setQuantities({});
    setAppliedCoupon(null);
  };

  const selectedOptions = useMemo(() => {
    const allOptions = serviceCategories.flatMap(c => c.options);
    return allOptions.filter(o => selectedIds.includes(o.id));
  }, [selectedIds, serviceCategories]);

  const getOptionHierarchy = (optionId: string) => {
    for (let i = 0; i < serviceCategories.length; i++) {
        const cat = serviceCategories[i];
        const optIdx = cat.options.findIndex(o => o.id === optionId);
        if (optIdx !== -1) {
            return `${i + 1}.${optIdx + 1}`;
        }
    }
    return '';
  };

  const subTotalPrice = useMemo(() => {
    return selectedOptions.reduce((total, option) => {
      const quantity = option.hasQuantity ? (quantities[option.id] || 1) : 1;
      const unitPrice = getUnitPrice(option, quantity);
      return total + (unitPrice * quantity);
    }, 0);
  }, [selectedOptions, quantities]);

  const discountPercentage = useMemo(() => {
    let basePercentage = 0;
    const count = selectedIds.length;

    // Adjusted thresholds to reach 30% for full selections
    if (count >= 18) basePercentage = 25;
    else if (count >= 12) basePercentage = 20;
    else if (count >= 8) basePercentage = 15;
    else if (count >= 5) basePercentage = 10;
    else if (count >= 3) basePercentage = 5;

    let bonusPercentage = 0;
    if (subTotalPrice > 10000) bonusPercentage = 5;

    const couponDiscount = appliedCoupon ? appliedCoupon.discount : 0;

    // Hard cap at 40% total (bundle + bonus + coupon)
    return Math.min(40, basePercentage + bonusPercentage + couponDiscount);
  }, [selectedIds.length, subTotalPrice, appliedCoupon]);

  const discount = useMemo(() => (subTotalPrice * discountPercentage) / 100, [subTotalPrice, discountPercentage]);
  const finalTotalPrice = useMemo(() => subTotalPrice - discount, [subTotalPrice, discountPercentage]);

  useEffect(() => {
    if (discountPercentage > prevDiscountPercentageRef.current) {
        setShowCelebration(true);
    }
    prevDiscountPercentageRef.current = discountPercentage;
  }, [discountPercentage]);

  const validateInfo = useCallback(() => {
    const { name, phone, email } = clientInfo;
    const isEmailValid = email && !emailError;
    if (!name || !phone || !isEmailValid) {
      setFormError(t.fillInfoAlert);
      return false;
    }
    setFormError('');
    return true;
  }, [clientInfo, emailError, t.fillInfoAlert]);

  const handleSendViaWhatsApp = () => {
    setFormError('');
    if (!validateInfo()) return;

    const formattedDate = proposalDate.toLocaleDateString(language === 'ar' ? 'ar-EG' : 'en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
    });

    const fullPhoneNumber = `${clientInfo.countryCode}${clientInfo.phone}`;

    const servicesText = selectedOptions.map(option => {
        const quantity = option.hasQuantity ? (quantities[option.id] || 1) : 1;
        const unitPrice = getUnitPrice(option, quantity);
        const price = unitPrice * quantity;
        const quantityText = option.hasQuantity ? ` (${quantity} × ${formatCurrency(unitPrice)})` : '';
        const hierarchy = getOptionHierarchy(option.id);
        return `${hierarchy} - ${option.name}${quantityText}: *${formatCurrency(price)}*`;
    }).join('\n');

    const couponInfo = appliedCoupon ? `\n*الكوبون المطبق:* ${appliedCoupon.code} (${appliedCoupon.discount}% خصم إضافي)` : '';

    const message = `
*${t.proposalTitle}*

*${t.clientInfoTitle}:*
${t.clientNameLabel}: ${clientInfo.name}
${t.clientPhoneLabel}: ${fullPhoneNumber}
${t.clientEmailLabel}: ${clientInfo.email}
${t.proposalDateLabel}: ${formattedDate}

*${t.selectedServicesTitle}:*
${servicesText}
${couponInfo}

*${t.priceSummaryTitle}:*
${t.subtotal}: ${formatCurrency(subTotalPrice)}
${language === 'en' ? t.discountLabel(discountPercentage) : `خصم (${discountPercentage}%)`}: -${formatCurrency(discount)}
*${t.totalPrice}: ${formatCurrency(finalTotalPrice)}*

${t.proposalTo(clientInfo.name)}
    `.trim().replace(/^\s+/gm, "");

    const whatsappNumber = '+905342006606';
    const encodedMessage = encodeURIComponent(message);
    const whatsappUrl = `https://wa.me/${whatsappNumber}?text=${encodedMessage}`;

    window.open(whatsappUrl, '_blank', 'noopener,noreferrer');
};

  const handleSubmission = () => {
    setFormError('');
    if (!validateInfo() || actionType) return;

    if (!isEmailConfigured()) {
        setFormError(t.emailConfigMissing);
        return;
    }

    setActionType('email');

    sendProposalEmails({
      clientInfo,
      selectedOptions,
      quantities,
      subTotalPrice,
      discount,
      discountPercentage,
      finalTotalPrice,
      isClientSubmission: true,
      t,
      selectedIds,
      proposalDate
    })
      .then((response) => {
        setShowSuccessScreen(true);
        setActionType(null);
      }, (err) => {
        setFormError(t.emailSendError);
        setActionType(null);
      });
  };

  return (
    <div className="bg-transparent min-h-screen">
      <Header 
        language={language}
        toggleLanguage={toggleLanguage}
      />
      <PrintHeader />
      <main className="max-w-4xl mx-auto p-4 md:p-8 space-y-8 print:p-0 print:mx-0 print:max-w-full pb-32 md:pb-40">
        <StaticSection 
          t={t}
          language={language}
          clientInfo={clientInfo}
          onClientInfoChange={handleClientInfoChange}
          emailError={emailError}
          proposalDate={proposalDate}
          isClientMode={false}
        />

        <PricingSection
          categories={serviceCategories}
          selectedIds={selectedIds}
          onServiceToggle={handleServiceToggle}
          quantities={quantities}
          onQuantityChange={handleQuantityChange}
          language={language}
          t={t}
          isClientMode={false}
        />

        <TermsAndConditions t={t} language={language} />
      </main>
      <Footer language={language} />
      <TotalBar
        subTotalPrice={subTotalPrice}
        finalTotalPrice={finalTotalPrice}
        discount={discount}
        discountPercentage={discountPercentage}
        onSendEmail={isClientMode ? handleSubmission : handleSendViaWhatsApp}
        onClearSelection={handleClearSelection}
        language={language}
        t={t}
        actionType={actionType}
        formError={formError}
        isClientMode={isClientMode}
        appliedCoupon={appliedCoupon}
        onApplyCoupon={setAppliedCoupon}
      />
      {showSuccessScreen && (
        <SuccessScreen 
            t={t}
            isClientMode={isClientMode}
            onClose={() => setShowSuccessScreen(false)}
        />
      )}
      {showCelebration && (
        <DiscountCelebration 
            t={t}
            discountPercentage={discountPercentage}
            savedAmount={discount}
            onClose={() => setShowCelebration(false)}
        />
      )}
    </div>
  );
}

export default App;

