            <div className={`flex flex-col gap-0.5 ${language === 'ar' ? 'items-end' : 'items-start'}`}>
                <span className={`text-5xl md:text-7xl font-black text-slate-900 transition-transform leading-tight ${pulseTotal ? 'animate-value-pop' : ''}`}>
