            </div>

            <div className={`flex flex-wrap gap-3 mt-3 items-center ${language === 'ar' ? 'flex-row-reverse' : 'flex-row'}`}>
              {discountText && (
                <p className="text-sm md:text-base text-blue-600 font-black bg-blue-50 px-4 py-2 rounded-2xl inline-block border border-blue-100/50 shadow-sm transition-all hover:bg-blue-100/30">
                  {discountText}
                </p>
              )}
              {discount > 0 && !isClientMode && (
                <p className="text-sm md:text-base text-green-600 font-black bg-green-50 px-4 py-2 rounded-2xl inline-block border border-green-100/50 shadow-sm transition-all hover:bg-green-100/30">
                  {t.youSaved(formatCurrency(discount))}
                </p>
              )}
            </div>

            {/* Improved Coupon Input Area */}
            <div className={`mt-5 flex flex-col gap-2 ${language === 'ar' ? 'items-end' : 'items-start'}`}>
              {!appliedCoupon ? (
                <div className={`flex items-stretch gap-2.5 w-full max-w-[340px] ${language === 'ar' ? 'flex-row-reverse' : 'flex-row'}`}>
                  <div className="relative flex-1 group">
                    <input
                      type="text"
                      value={couponCode}
                      onChange={(e) => { setCouponCode(e.target.value); if(couponError) setCouponError(false); }}
                      onKeyDown={(e) => e.key === 'Enter' && handleApplyCoupon()}
                      placeholder={t.couponPlaceholder}
                      className={`w-full text-base h-12 px-5 bg-slate-50 text-slate-900 border-2 ${couponError ? 'border-red-400 bg-red-50 text-red-900' : 'border-slate-200 group-hover:border-slate-300 focus:border-blue-500 shadow-sm'} rounded-2xl focus:outline-none transition-all duration-200 placeholder:text-slate-400 font-black uppercase tracking-wider`}
                    />
                  </div>
