                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right Side: Action Buttons */}
        <div className="flex flex-col gap-3 flex-shrink-0 w-full md:w-auto mt-4 md:mt-0">
          {formError && (
            <p role="alert" className={`text-sm text-red-600 font-black mb-1 ${language === 'ar' ? 'text-right' : 'text-left'}`}>
              {formError}
            </p>
          )}
          <div className={`flex flex-col sm:flex-row items-center gap-4 ${language === 'ar' ? 'sm:flex-row-reverse' : ''}`}>
            <button
              onClick={onSendEmail}
              disabled={isSending}
              className="w-full sm:w-auto min-w-[260px] justify-center flex items-center gap-4 px-10 py-5 border border-transparent text-xl font-black rounded-3xl shadow-[0_20px_50px_rgba(37,99,235,0.3)] text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-4 focus:ring-blue-500/30 disabled:bg-blue-300 transition-all active:scale-[0.96] uppercase tracking-wider"
            >
              {isClientMode ? (
                  isSending ? t.sending : t.sendProposal
              ) : (
                <>
                  <WhatsAppIcon />
                  {t.sendEmail}
